mapper.select:
SELECT s.*, c.class_name, CASE s.gender WHEN 1 THEN '男' ELSE '女' END as gender_name FROM student_info s LEFT JOIN class_info c ON s.class_id = c.id WHERE 1=1
AND (s.name LIKE CONCAT('%', #{keyword}, '%') OR s.student_no LIKE CONCAT('%', #{keyword}, '%'))
AND s.class_id = #{classId}
AND s.status = #{status}
ORDER BY s.create_time DESC
